    print("\n=== Test P7-LEX-10: invalid q_fields returns INVALID_QUERY ===")
    vault = _lex_vault()
    build_index(vault)

    result = query(vault, {}, q="data", q_fields=["body", "nosuchfield"])

    assert result["status"] == "error"
    assert result["error"] == "INVALID_QUERY"
