    with _p22_temp_vault() as tmpdir:
        result = start_session(
            "test-vault",
            current_project="Phase 22",
            current_topic="Testing",
            user_goal="Verify session state",
            active_vault="test-vault",
            _vault_path=tmpdir,
        )

    assert result["status"] == "ok", f"Expected ok: {result}"
