def _p30f_phase_block(css: str) -> str:
    """Return only the Phase 30F section of global.css, for scoped asserts."""
    marker = "Phase 30F"
    idx = css.find(marker)
    assert idx != -1, "global.css must contain a Phase 30F section comment"
    return css[idx:]


