def _tokens_in_block(block: str) -> set:
    """Phase 30F helper: extract --cve-* token names from a CSS block.
    Re-defined here in case the earlier Phase 30B helper is not in
    scope at call time."""
    import re
    return set(re.findall(r"(--cve-[A-Za-z0-9_-]+)\s*:", block))


